-- Ensure default admin auth user exists
DO $$
DECLARE
  v_admin_id uuid;
BEGIN
  SELECT id INTO v_admin_id FROM auth.users WHERE email = 'dev@gotham.design' LIMIT 1;
  IF v_admin_id IS NULL THEN
    v_admin_id := gen_random_uuid();
    INSERT INTO auth.users (
      id, instance_id, aud, role, email, encrypted_password,
      email_confirmed_at, confirmation_token, recovery_token,
      email_change, email_change_token_new, email_change_token_current,
      phone_change, phone_change_token, reauthentication_token,
      created_at, updated_at, raw_app_meta_data, raw_user_meta_data
    ) VALUES (
      v_admin_id, '00000000-0000-0000-0000-000000000000', 'authenticated', 'authenticated', 'dev@gotham.design',
      crypt('changeme', gen_salt('bf')), now(), '', '',
      '', '', '', '', '', '',
      now(), now(), '{}'::jsonb, '{}'::jsonb
    );
  END IF;
END $$;

-- Ensure default admin profile exists/updated
INSERT INTO public.profiles (id, email, full_name, app_role, organization_id, updated_at)
SELECT
  u.id, 'dev@gotham.design', 'Dev Admin', 'admin',
  (SELECT id FROM public.organization ORDER BY created_date LIMIT 1),
  now()
FROM auth.users u
WHERE u.email = 'dev@gotham.design'
ON CONFLICT (id) DO UPDATE SET
  email = EXCLUDED.email,
  app_role = 'admin',
  organization_id = COALESCE(EXCLUDED.organization_id, public.profiles.organization_id),
  updated_at = now();

COMMIT;
